// Fetch existing keywords from NocoDB to dedup against
const _https = require('https');
const _http = require('http');
const { URL } = require('url');

function fetchFn(urlStr, opts = {}) {
  return new Promise((resolve, reject) => {
    const u = new URL(urlStr);
    const mod = u.protocol === 'https:' ? _https : _http;
    const reqOpts = {
      hostname: u.hostname, port: u.port,
      path: u.pathname + u.search,
      method: opts.method || 'GET',
      headers: opts.headers || {},
    };
    const req = mod.request(reqOpts, (res) => {
      const chunks = [];
      res.on('data', (c) => chunks.push(c));
      res.on('end', () => {
        const body = Buffer.concat(chunks).toString();
        resolve({ ok: res.statusCode >= 200 && res.statusCode < 300, status: res.statusCode, json: () => Promise.resolve(JSON.parse(body)), text: () => Promise.resolve(body) });
      });
    });
    req.on('error', reject);
    if (opts.body) req.write(typeof opts.body === 'string' ? opts.body : JSON.stringify(opts.body));
    req.end();
  });
}

// Get existing keywords
const res = await fetchFn($env.NOCODB_BASE_URL + '/Keywords?fields=keyword&limit=1000', {
  headers: { 'xc-auth': $env.NOCODB_API_TOKEN },
});
const data = await res.json();
const existing = (data.list || []).map(r => r.keyword);

// Get active tickers from recent insider trades (top 20)
const tradesRes = await fetchFn('https://api.financialdatasets.ai/api/v1/insider-trades?limit=50', {
  headers: { 'X-API-Key': $env.FINANCIAL_DATASETS_API_KEY },
});
let tickers = [];
if (tradesRes.ok) {
  const trades = await tradesRes.json();
  const tickerSet = new Set();
  (trades.insider_trades || []).forEach(t => { if (t.ticker) tickerSet.add(t.ticker); });
  tickers = [...tickerSet].slice(0, 20);
}

return [{ json: { existing_keywords: existing, tickers, active_blogs: ['insiderbuying'] } }];

