// Write keywords to NocoDB
const _https = require('https');
const _http = require('http');
const { URL } = require('url');

function fetchFn(urlStr, opts = {}) {
  return new Promise((resolve, reject) => {
    const u = new URL(urlStr);
    const mod = u.protocol === 'https:' ? _https : _http;
    const reqOpts = { hostname: u.hostname, port: u.port, path: u.pathname + u.search, method: opts.method || 'GET', headers: opts.headers || {} };
    const req = mod.request(reqOpts, (res) => {
      const chunks = [];
      res.on('data', (c) => chunks.push(c));
      res.on('end', () => {
        const body = Buffer.concat(chunks).toString();
        resolve({ ok: res.statusCode >= 200 && res.statusCode < 300, json: () => Promise.resolve(JSON.parse(body)) });
      });
    });
    req.on('error', reject);
    if (opts.body) req.write(typeof opts.body === 'string' ? opts.body : JSON.stringify(opts.body));
    req.end();
  });
}

const result = $input.first().json;
let written = 0;

for (const blog of result.blogs || []) {
  for (const kw of blog.keywords || []) {
    await fetchFn($env.NOCODB_BASE_URL + '/Keywords', {
      method: 'POST',
      headers: { 'xc-auth': $env.NOCODB_API_TOKEN, 'Content-Type': 'application/json' },
      body: JSON.stringify({
        keyword: kw.keyword,
        blog: kw.blog,
        ticker: kw.keyword.match(/\b([A-Z]{1,5})\b/)?.[1] || '',
        article_type: kw.article_type,
        search_volume: kw.search_volume,
        difficulty: kw.difficulty,
        cpc: kw.cpc,
        intent_multiplier: kw.intent_multiplier,
        priority_score: kw.priority_score,
        secondary_keywords: JSON.stringify([]),
        status: 'new',
      }),
    });
    written++;
  }
}

return [{ json: { ...result, written } }];

